var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"응......?","JPN":"ん……？","ENG":"Huh?","TWN":"嗯……？"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"왜 그래, 신입? 괜히 한눈 팔다 길 잃어버리면 큰일난다?","JPN":"どうしたの、新入り？　よそ見をして道に迷ったら大変なことになるよ？","ENG":"What's wrong, newbie? Keep your eyes up front or you'll get lost.","TWN":"怎麼了，新來的？可別恍神了，小心迷路。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"통로를 열 수 있는 건 일주일에 한 번 정도야.","JPN":"通路を開けられるのは、一週間に一回くらいなの。","ENG":"We can open the portal only about once a week.","TWN":"開通道的機會，一周只有一次。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"같이 못 나가면 그동안 꼼짝없이 여기 갇혀 있어야 할 걸?","JPN":"一緒に出ないと、ずっとここに閉じ込められる羽目になるんだよ？","ENG":"If you don't leave with us, you'll be stuck here the entire time!","TWN":"如果不能一起出去的話，就只能困在這裡。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"뭐, 내가 그랬다는 건 아니고...... 흠흠!","JPN":"まあ、私にそんな経験があったわけじゃないけど……ふんふん！","ENG":"I'm not saying it happened to me or anything... Ahem!","TWN":"我不是說我被困過……咳咳！"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아, 미안해. 아까부터 무슨 소리가 들리는 거 같아서.","JPN":"あ、ごめんなさい。さっきから何か音が聞こえる気がして……","ENG":"Sorry. It's just that I felt like I heard something for a while now.","TWN":"啊，抱歉。從剛剛開始好像一直有什麼聲音。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"소리? 무슨 소리?","JPN":"音？　何の音？","ENG":"Heard what?","TWN":"聲音？什麼聲音？"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"누군가가 부르고 있는 것 같은 소리 말이야.","JPN":"誰かが呼んでいるような音が聞こえるんです。","ENG":"Like someone's calling me.","TWN":"好像是有人叫我的聲音。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"여기 온 뒤로 계속 들려. 처음엔 바람 소리인 줄 알았는데......","JPN":"ここに来てからずっとです。最初は風の音かと思ったけど……","ENG":"I kept hearing it ever since I got here. At first I thought it was the wind...","TWN":"來到這裡之後我就一直聽到這聲音，剛開始我還以為是風聲……"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저기 저 쪽, 바위 절벽 너머 쪽에서 들려오는 것 같아.","JPN":"あそこ、岩の崖の向こうから聞こえてくる気がします。","ENG":"But I think it's coming from over there, beyond that rocky cliff.","TWN":"好像是從那個岩石峭壁的後面傳出來的。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"어이 어이! 멋대로 어딜 가는 거야?","JPN":"ちょ、ちょっと！　勝手にどこにいくのよ！","ENG":"Hey, hey! Where are you going?","TWN":"喂，喂！妳去哪裡啊？"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그러다가 라우라에게 혼나기라도 하면...... 어라?!","JPN":"そんなことしてラウラに怒られたら……あれ！？","ENG":"You could get in trouble with Laura... Huh?","TWN":"小心又被蘿拉罵……咦？！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_STREGA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_STREGA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저게...... 뭐야?","JPN":"あれ……何でしょう？","ENG":"What... is that?","TWN":"那是……什麼？"},"stage":{"bg":"SS_STREGA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"나, 나도 몰라. 이런 곳엔 처음 와 본다고.","JPN":"わ、私にもわからない。こんな所に来るのは初めてだから。","ENG":"I-I have no idea. I've never been all the way out here either.","TWN":"我、我也不知道。我也是第一次來這裡。"},"stage":{"bg":"SS_STREGA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그냥 봐서는 무슨 섬 위에 세워진 궁전 같은데......","JPN":"ぱっと見は、島の上に建てられた宮殿のようだけど……","ENG":"It looks like some kind of a castle on an island...","TWN":"乍一看，好像是建在島上的宮殿。"},"stage":{"bg":"SS_STREGA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"가 보자.","JPN":"行ってみましょう。","ENG":"Let's go check it out.","TWN":"去看看吧。"},"stage":{"bg":"SS_STREGA_01","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};